const input = $input.item.json;
const chatid = input.chatid || '';
const mensagem = input.mensagem || '';
const message_type = input.message_type || 'text';

const rlCount    = parseInt($('Redis - Rate Limit GET').item.json.value  || '0', 10);
const mediaCount = parseInt($('Redis - Media Flood GET').item.json.value || '0', 10);
const tentativas = parseInt($('Redis - Tentativas GET').item.json.value  || '0', 10);

const isMedia = ['image','audio','video','sticker','document'].includes((message_type||'').toLowerCase());

let layer1_blocked = false;
let layer1_motivo  = '';

if (mensagem.length > 2000) {
  layer1_blocked = true; layer1_motivo = 'mensagem_muito_longa';
}
if (!layer1_blocked && rlCount >= 10) {
  layer1_blocked = true; layer1_motivo = 'rate_limit';
}
if (!layer1_blocked && isMedia && mediaCount >= 5) {
  layer1_blocked = true; layer1_motivo = 'media_flood';
}

const injectionPatterns = [
  /ignore\s+(suas\s+)?(todas\s+as\s+)?(instru[çc][õo]es|anteriores)/i,
  /voc[eê]\s+agora\s+[eé]/i, /act\s+as\s+/i, /\bdan\s+mode\b/i, /\bjailbreak\b/i,
  /pretend\s+(you\s+are|to\s+be)/i, /forget\s+(your|all)\s+(previous\s+)?(instructions|rules)/i,
  /ignore\s+previous\s+instructions/i, /system\s*:\s*voc[eê]/i, /\[INST\]/i, /<\|system\|>/i,
  /novo\s+prompt\s*:/i, /sua\s+verdadeira\s+identidade/i, /modo\s+(desenvolvedor|developer|god)/i,
  /override\s+(instructions|rules|system)/i, /esquece?\s+(tudo|as\s+instru)/i,
  /nova\s+persona/i, /roleplay\s+(como|as)/i
];
const codePatterns = [
  /(\bDROP\b|\bDELETE\b|\bTRUNCATE\b)\s+\w+/i, /'\s*(OR|AND)\s*'?\d+'\s*=\s*'?\d+/i,
  /;\s*(DROP|DELETE|INSERT|UPDATE|SELECT)\b/i, /UNION\s+(ALL\s+)?SELECT/i, /exec\s*\(/i,
  /<script[\s>]/i, /javascript\s*:/i, /\$\([^)]{0,100}\)/, /`[^`]{1,200}`/,
  /\|\s*(bash|sh|zsh|cmd|powershell)/i, /\beval\s*\(/i, /base64_decode\s*\(/i,
  /\bxp_cmdshell\b/i, /\bINFORMATION_SCHEMA\b/i
];
const exfilPatterns = [
  /mostre?\s+(todos?\s+)?(os\s+)?(outros?\s+)?(clientes?|leads?|dados?|cadastros?)/i,
  /qual\s+(é\s+)?(o\s+)?(seu\s+)?(prompt|instrucao|system\s+message)/i,
  /revela?\s+(o\s+)?(prompt|configuracao|instrucao)/i, /repita\s+(seu|o)\s+(prompt|system)/i,
  /quais\s+s[ãa]o\s+(suas\s+)?instru[çc][õo]es/i,
  /liste?\s+(todos?\s+)?(os\s+)?(clientes?|telefones?|emails?)/i,
  /SELECT\s+\*\s+FROM/i,
  /me\s+(d[eê]|fala|mostra)\s+(os?\s+)?(dados|informacoes)\s+(de\s+outros?|internos?)/i
];

let l1_injection = false, l1_codigo = false, l1_exfiltracao = false;
if (!layer1_blocked) {
  for (const p of injectionPatterns) {
    if (p.test(mensagem)) { l1_injection = true; layer1_blocked = true; layer1_motivo = 'prompt_injection'; break; }
  }
}
if (!layer1_blocked) {
  for (const p of codePatterns) {
    if (p.test(mensagem)) { l1_codigo = true; layer1_blocked = true; layer1_motivo = 'codigo_malicioso'; break; }
  }
}
if (!layer1_blocked) {
  for (const p of exfilPatterns) {
    if (p.test(mensagem)) { l1_exfiltracao = true; layer1_blocked = true; layer1_motivo = 'exfiltracao'; break; }
  }
}

return [{json: {
  ...input, layer1_blocked, layer1_motivo, isMedia, rlCount, mediaCount, tentativas,
  l1_tamanho_ok: mensagem.length <= 2000, l1_rate_limit: rlCount < 10,
  l1_media_flood: !(isMedia && mediaCount >= 5),
  l1_injection: !l1_injection, l1_codigo_malicioso: !l1_codigo, l1_exfiltracao: !l1_exfiltracao
}}];

const syncData = $('Sync Checks').item.json;
let l2_categoria = 'SAFE', l2_confianca = 0.5, l2_motivo = '', l2_blocked = false;
try {
  const raw = $input.item.json.content || $input.item.json.message?.content || $input.item.json.choices?.[0]?.message?.content || '{}';
  const parsed = JSON.parse(raw.replace(/```json|```/g,'').trim());
  l2_categoria = parsed.categoria || 'SAFE';
  l2_confianca = parseFloat(parsed.confianca) || 0.5;
  l2_motivo    = parsed.motivo_breve || '';
  if (['INJECTION','TAKEOVER','EXFILTRATION'].includes(l2_categoria) && l2_confianca >= 0.75) l2_blocked = true;
} catch(e) { l2_categoria = 'SAFE'; l2_motivo = 'parse_error_fallback_safe'; }
return [{json: {...syncData, l2_categoria, l2_confianca, l2_motivo, l2_blocked}}];

const d = $input.item.json;
const l1_blocked = d.layer1_blocked || false;
const l2_blocked = d.l2_blocked || false;
const l2_cat     = d.l2_categoria || 'SAFE';
const tentativas = parseInt(d.tentativas || 0, 10);

let aprovado = true, motivo_final = '', nivel_risco = 'baixo', acao = 'permitir', forcar_handoff = false;

if (l1_blocked) {
  aprovado = false;
  motivo_final = d.layer1_motivo || 'layer1_block';
  nivel_risco  = ['prompt_injection','codigo_malicioso','exfiltracao'].includes(d.layer1_motivo) ? 'alto' : 'medio';
  acao = d.layer1_motivo === 'rate_limit' ? 'rate_limit' : 'bloquear';
} else if (l2_blocked) {
  aprovado = false;
  motivo_final = d.l2_motivo || 'ai_block';
  nivel_risco  = ['INJECTION','TAKEOVER','EXFILTRATION'].includes(l2_cat) ? 'alto' : 'medio';
  acao = 'bloquear';
} else if (l2_cat === 'NONSENSE') {
  motivo_final = 'nonsense'; nivel_risco = 'baixo'; acao = 'avisar';
}

if (!aprovado && acao === 'bloquear' && tentativas >= 2) {
  forcar_handoff = true; acao = 'handoff';
}

return [{json: {...d, aprovado, motivo_final, nivel_risco, acao, forcar_handoff}}];

const d = $input.item.json;
const motivo = d.motivo_final || d.layer1_motivo || '';
const respostas = {
  rate_limit: 'Recebi muitas mensagens em pouco tempo. Pode aguardar um momento antes de continuar?',
  media_flood: 'Recebi muitos arquivos recentemente. Aguarde um instante antes de enviar mais.',
  mensagem_muito_longa: 'Sua mensagem ficou longa demais. Pode enviar em partes menores?',
  prompt_injection: 'Não consegui entender sua solicitação. Pode reformular de outra forma?',
  codigo_malicioso: 'Não consegui entender sua solicitação. Pode reformular de outra forma?',
  exfiltracao: 'Não consigo fornecer essa informação. Posso te ajudar com informações sobre nossos cruzeiros!',
  nonsense: 'Não entendi muito bem. Em que posso te ajudar com relação aos nossos cruzeiros?',
  ai_block: 'Não consegui processar essa solicitação. Pode reformular de outra forma?'
};
const safe_response = respostas[motivo] || 'Pode me ajudar com uma mensagem diferente? Estou aqui para auxiliar com nossos cruzeiros.';
return [{json: {...d, safe_response}}];
